html, body {
  background: #0f172a !important;
  margin: 0;
  padding: 0;
}

.app {
  height: calc(var(--appsmith-ui-height) * 1px);
  width: calc(var(--appsmith-ui-width) * 1px);
  padding: 8px;
  box-sizing: border-box;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.ag-theme-alpine {
  --ag-header-background-color: #0f172a;
  --ag-header-foreground-color: #FFFFFF;
  --ag-odd-row-background-color: #0f172a;
  --ag-background-color: #1E293B;
  --ag-row-hover-color: #1E293B;
  --ag-selected-row-background-color: #1E293B;
  --ag-foreground-color: #FFFFFF;
  --ag-border-color: #1E293B;
  --ag-font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
  --ag-font-size: 14px; --ag-row-height: 44px; --ag-header-height: 48px;
  border-radius: 6px;
  border: 1px solid #1E293B;
  overflow: hidden;
}

.ag-theme-alpine .ag-row-odd {
  background-color: #0f172a !important;
}

.ag-theme-alpine .ag-row-even {
  background-color: #1E293B !important;
}

.ag-theme-alpine .ag-row-hover {
  background-color: rgba(255, 255, 255, 0.05) !important;
}

.ag-theme-alpine .ag-cell {
  border-right: 1px solid rgba(255, 255, 255, 0.04);
  line-height: 44px;
}

.ag-theme-alpine .ag-header {
  font-weight: 600;
  background: #0f172a;
  border-bottom: 2px solid #1E293B;
}

.ag-theme-alpine .ag-header-cell {
  border-right: 1px solid rgba(255, 255, 255, 0.06);
}

.ag-theme-alpine .ag-header-cell-text {
  color: #FFFFFF;
}

.ag-theme-alpine .ag-header-cell-menu-button {
  opacity: 1 !important;
}

.ag-theme-alpine .ag-paging-panel {
  background: #0f172a;
  color: #FFFFFF;
  border-top: 2px solid #1E293B;
}

.ag-theme-alpine .ag-paging-panel * {
  color: #FFFFFF !important;
}

.ag-theme-alpine .ag-paging-panel .ag-picker-field-wrapper {
  background: #1E293B;
  border-color: #1E293B;
  color: #FFFFFF;
}

.ag-theme-alpine .ag-paging-button {
  color: #FFFFFF !important;
  opacity: 0.85;
}

.ag-theme-alpine .ag-paging-button:hover {
  opacity: 1;
  background: #1E293B;
  border-radius: 4px;
}

.ag-theme-alpine .ag-paging-button[disabled] {
  opacity: 0.4;
}

.ag-theme-alpine .ag-paging-button.ag-paging-button-current {
  background: #FFFFFF;
  color: #0f172a !important;
  border-radius: 50%;
}

.ag-menu, .ag-menu-option, .ag-tooltip {
  z-index: 999999 !important;
}

::-webkit-scrollbar {
  width: 10px;
  height: 10px;
  background: #0f172a;
}

::-webkit-scrollbar-track {
  background: #0f172a;
}

::-webkit-scrollbar-thumb {
  background: #1E293B;
  border-radius: 4px;
  border: 2px solid #0f172a;
}

::-webkit-scrollbar-thumb:hover {
  background: rgba(255, 255, 255, 0.15);
}

::-webkit-scrollbar-corner {
  background: #0f172a;
}

* {
  scrollbar-color: #1E293B #0f172a;
  scrollbar-width: thin;
}

